var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"<color=#ff3636>죽어어어어!!!!</color>","JPN":"<color=#ff3636>死ねええええ！！！！</color>","ENG":"<color=#ff3636>DIEEEE!!!</color>","TWN":"<color=#ff3636>去死！！！！</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"……아직이다.","JPN":"……まだだ。","ENG":"...Not just yet.","TWN":"……還沒。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"레노어의 공격은 분명히 통했다.","JPN":"レノアの攻撃は確かに効いた。","ENG":"Lenore's attack definitely hit.","TWN":"蕾諾雅的攻擊明明有奏效，"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하지만……","JPN":"しかし……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"실험체가 상처를 입을 때마다, 결계옥의 힘이 빠져나가고 있군.","JPN":"実験体が傷つくたびに、結界玉の力が抜けている。","ENG":"Whenever the test subject is hit, Akaitama loses its power.","TWN":"實驗體每次受傷時，結界玉石的力量都在流失。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그릇을 삼켜야 할 신의 영혼이…… 오히려 그릇에게 흡수되고 있는 건가?","JPN":"器を飲み込むはずの神の魂が……むしろ器に取り込まれているのか？","ENG":"Could this mean that the god's soul which is supposed to consume the vessel... is getting absorbed into her?","TWN":"神的靈魂原本應該要吞噬掉器皿的……結果反而是器皿在吸收神的靈魂嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"<color=#ff3636>왜…… 죽지…… 않아?</color>","JPN":"<color=#ff3636>なぜ……死な……ない？</color>","ENG":"<color=#ff3636>Why... won't you... die?</color>","TWN":"<color=#ff3636>你……為什麼……還沒死？</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"<color=#ff3636>왜…… 베어도…… 베어도…… 죽지…… 않…… 는 거야?</color>","JPN":"<color=#ff3636>なぜ……斬っても……斬っても……死な……ないの？</color>","ENG":"<color=#ff3636>Why... No matter... how much I slash... Why... won't... you die?</color>","TWN":"<color=#ff3636>為什麼……怎麼砍……怎麼砍……都……砍不死……？</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"나의 검은 네놈의 정처없이 헤매는 칼날에 당할 만큼 무르지 않기 때문이지.","JPN":"私の刀はお前の行き場のない刃にやられるほどやわじゃないからだ。","ENG":"That is because my blade is not weak enough for your wandering blade to chip it.","TWN":"因為我的劍沒有弱到會被你猶疑不定的刀刃砍斷。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"제 아무리 강대한 힘도, 뛰어난 기교도, 결국 운명 앞에서 허물어지고 마는 것이라면……","JPN":"いくら巨大な力も、優れた技巧も、結局運命の前で崩れてしまうものなら……","ENG":"No matter how strong I am, or how excellent my technique is... If they all collapse in the face of fate...","TWN":"若是無論多麼強大的力量，多麼出色的技巧，最後都會在命運面前瓦解的話……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"나는 내 검으로 그 운명을 끊어내겠다.","JPN":"私は私の刀でその運命を断つ。","ENG":"I will end the fate with my blade.","TWN":"那我會選擇用我的劍斬斷命運。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"<color=#ff3636>이…… 건 말도……</color>","JPN":"<color=#ff3636>そんな……バカな……</color>","ENG":"<color=#ff3636>Don't... kid your–</color>","TWN":"<color=#ff3636>怎……麼可……</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"<color=#ff3636>아…… 버…… 지……</color>","JPN":"<color=#ff3636>お……父……様……</color>","ENG":"<color=#ff3636>Fa... ther...</color>","TWN":"<color=#ff3636>父……親……</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"이겼습니다, 언니.","JPN":"勝ちました、姉上。","ENG":"I won, Chinatsu.","TWN":"我贏了，姊姊。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"하지만……","JPN":"しかし……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"죽음을 두려워하지 않게 된다는 게 이런 의미인 줄 알았더라면……","JPN":"死を恐れなくなるということがこのような意味であることをもっと早くに知っていれば……","ENG":"If I had known that not fearing death meant this...","TWN":"要是早知道無懼死亡是這個意思……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"언니를 지키기 위한 역신베기의 대가가 이런 것인 줄 알았더라면……","JPN":"姉上をお守りするための大蛇薙剣の代償がこんなことだと知っていれば……","ENG":"That the price of completing Orochinagi that was supposed to protect you was this...","TWN":"要是早知道完成守護姊姊的瘟神斬，要付出這樣的代價……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"처음부터 얻고자 하지도 않았을 텐데요.","JPN":"最初から欲することもなかったのに。","ENG":"Then I would have never attempted to obtain it in the first place.","TWN":"那我從一開始就不會想要得到它。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"언니, 여기 계셨네요.","JPN":"姉上、ここにいらしたのですね。","ENG":"Chinatsu, there you are.","TWN":"姊姊，你在這裡喔。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"갑자기 사라지셔서 어르신들이 걱정하고 있습니다.","JPN":"いきなりいなくなられて、みんな心配しています。","ENG":"The elders were worried when you suddenly disappeared.","TWN":"你突然不見人影，長輩們都很擔心呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"아, 치후유……","JPN":"あ、千冬……","ENG":"Oh, Chifuyu...","TWN":"喔，是千冬……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"미안, 나비를 쫓아다니다 길을 잃어버렸어.","JPN":"ごめん、蝶々を追って道に迷ってしまったの。","ENG":"My apologies, I got lost whilst chasing a butterfly.","TWN":"對不起，我在追蝴蝶，追著追著就迷路了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"언니 참 철부지 같지?","JPN":"私って、本当に子どもっぽいわよね？","ENG":"Aren't I a klutz sometimes?","TWN":"姊姊很不懂事對吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"울고…… 계셨습니까?","JPN":"泣いて……いたんですか？","ENG":"Were you... crying?","TWN":"你……在哭嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"정말? 나도 모르게 먼지가 들어갔나보다.","JPN":"本当？　目にゴミが入ったみたい。","ENG":"Was I? Perhaps I got something in my eye.","TWN":"有嗎？應該是沙子跑到眼睛裡了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"하지만 이제 괜찮아. 치후유가 왔으니까.","JPN":"でも、もう大丈夫。千冬が来たから。","ENG":"But I am fine now. Because you are here, Chifuyu.","TWN":"不過你來了就好，現在沒事了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"……그렇군요.","JPN":"……そうですか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"어서 가자. 앞장서렴.","JPN":"急ぎましょ。先に行って。","ENG":"Let us go. Please lead the way.","TWN":"快回去吧，你來帶路。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"훌륭한 당주가 되려면, 아직 배워야 할 것들이 많으니까.","JPN":"立派な当主になるためには、まだ教わることがたくさんあるから。","ENG":"I still have a lot to learn to be a great leader of the family.","TWN":"要想成為優秀的堂主，我要學的東西還很多。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"언니…… 아니, 당주님.","JPN":"姉上……いや、当主。","ENG":"Chinat– I mean, Lady Nanahara.","TWN":"姊姊……不對，堂主。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"힘든 일이 있으실 땐, 저를 찾아주십시오.","JPN":"辛いことがあったときは、私のところに来てください。","ENG":"If there is anything on your mind, you can always come to me.","TWN":"遇到困難的時候就來找我。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"어르신들은 모르는 저만의 수련장소가 많이 있습니다.","JPN":"誰も知らない私だけの修練場がたくさんあります。","ENG":"I have a secret training spot that even the elders don't know about.","TWN":"我有很多長輩們不知道的秘密基地。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"아하하, 난 정말 타고난 운명인가 봐.","JPN":"あはは、私は本当に運命に選ばれたのかも。","ENG":"Ah hah hah. Maybe fate has blessed me.","TWN":"哈哈哈，我好像真是天選之人呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"어쩌다 이런 듬직한 동생을 갖게 된 걸까?","JPN":"どうやってこんな頼もしい妹ができたのかな？","ENG":"I could not have asked for a better little sister than you.","TWN":"不然怎麼會有這麼可靠的妹妹呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"노…… 놀리지 마십시오.","JPN":"か……からかわないでください。","ENG":"P-please don't tease me.","TWN":"你……別鬧我。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"놀리는 게 아니거든?","JPN":"からかってるわけじゃないけど？","ENG":"Did I?","TWN":"才不是鬧你的！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_YOUNG","text":{"KOREA":"그리고 업어줘! 걷느라 다리 아파!","JPN":"あとおんぶして！　歩いたから足痛い！","ENG":"I want you to carry me! My legs hurt from all the walking!","TWN":"還有，揹我！走路走到我的腳好痛！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"으아앗?! 그렇게 뛰어오르시면……!","JPN":"うわあ！？　そんなに飛んだら……！","ENG":"Huh?! If you suddenly jump like that...!","TWN":"哎呀呀？！你這樣跳上來，我……！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유……?","JPN":"千冬……？","ENG":"Chifuyu...?","TWN":"千冬……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"울고 있는 거니?","JPN":"泣いているの？","ENG":"Are you crying?","TWN":"你在哭嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주…… 님?","JPN":"当主……？","ENG":"Lady... Nanahara?","TWN":"堂主……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"정말로…… 깨어나신 겁니까?","JPN":"本当に目覚めたんですか？","ENG":"Are you... really awake?","TWN":"您真的……清醒了嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러게……","JPN":"そうね……","ENG":"I believe so...","TWN":"是啊……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"긴 꿈을 꾼 것 같은데…… 지금은 괜찮아.","JPN":"長い夢を見ていた気がするけど……今は大丈夫。","ENG":"I feel like I dreamt for a long time... But I am all right now.","TWN":"我好像做了一個很長的夢……現在沒事了。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"결계옥은…… 어떻게 됐니?","JPN":"結界玉は……どうなったの？","ENG":"Akaitama... Did we retrieve it?","TWN":"結界玉石……怎麼樣了？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"빼앗기는 것은 막았습니다만……","JPN":"奪われることは防げましたが……","ENG":"We were able to retrieve it, but...","TWN":"雖然成功阻止它被搶走……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그 과정에서 일부는 제 몸에 깃들고 말았습니다.","JPN":"その過程で、一部は私の体に宿ってしまいました。","ENG":"During the process, a part of it has been absorbed into my body.","TWN":"但過程中有一部分滲入到我的身體裡。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어찌됐든 다행이다.","JPN":"でも、よかった。","ENG":"I am relieved.","TWN":"總之真是太好了。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"예?","JPN":"はい？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네가 이렇게 무사한 모습으로 내 앞에 있어줘서 기뻐.","JPN":"あなたがこうやって私の前に無事でいてくれて嬉しい。","ENG":"I am glad that you are here beside me, and safe.","TWN":"看到你這樣平安地站在我面前，我很開心。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"의식이 희미해져갈 때 말이야.","JPN":"意識が遠のく時にね。","ENG":"When my consciousness was fading...","TWN":"在我的意識逐漸變得模糊之際。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"세상이 어찌되어도 좋으니, 치후유만은 무사했으면 좋겠다고 생각했거든.","JPN":"世界なんてどうでもいいから、千冬だけは無事でいてほしいと思ったの。","ENG":"I thought, I do not care what happens to the world... As long as Chifuyu is safe.","TWN":"我就在想，世界變成什麼樣都無所謂，我只要千冬平安就好。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주님…… 어찌 그런 말씀을……!","JPN":"当主、どうしてそのようなお言葉を……！","ENG":"Lady Nanahara... Why would you think that...?!","TWN":"堂主……您怎麼這麼說……！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"정말로 다행이야. 정말로……","JPN":"本当によかった。本当に……","ENG":"However, I am immensely relieved...","TWN":"真是太好了，真的……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"무사해서 다행이야, 내 동생.","JPN":"無事でよかった、私の妹。","ENG":"I am glad you are safe, my little sister.","TWN":"幸好你平安無事，我的妹妹。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"저도요.","JPN":"私もです。","ENG":"As I am for you.","TWN":"我也是，"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"언니.","JPN":"姉さん。","ENG":"Chinatsu.","TWN":"姊姊。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"내 동생…… 몸이 엄청 뜨거워.","JPN":"千冬……体がすごく熱いね。","ENG":"Your body... it feels like it is burning.","TWN":"妹妹……你的身體很燙。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그게, 아무래도 명부신의 영혼에 영향을 받은 것 같습니다만…….","JPN":"それが、どうやら冥府の神の魂に影響を受けたみたいですが……","ENG":"I think... that is due to the influence of the Nether God's soul within me.","TWN":"好像是因為受冥府神靈魂的影響……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"역시 이런 통제도 안 되는 몸으론 당주님께 폐가 되지 않을지.","JPN":"やはり統制の効かないこの体では当主の迷惑になるのでは。","ENG":"But I wish not to be a burden to you when I am still not able to control it fully.","TWN":"我的身體現在變得無法控制，不知道會不會對堂主造成困擾。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"너만 곁에 있으면……","JPN":"あなたさえそばにいれば……","ENG":"With you by my side...","TWN":"只要你在我身邊……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"겨울에 추울 걱정은 덜겠구나.","JPN":"冬の寒さを心配しなくてもよさそうね。","ENG":"I will not have to worry about the cold in winter.","TWN":"冬天也不怕冷了呢。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그렇습니까?","JPN":"そうなのですか？","ENG":"Is that so?","TWN":"是嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"뭐…… 이거면 됐나?","JPN":"まあ……めでたしかのう？","ENG":"Well, I guess this'll do.","TWN":"嗯……這樣就可以了嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};